// ===== Build dead-stock snapshots + per-product rows from the Odoo read_group results =====
const CFG = $('Config').first().json;
const DEAD = Number(CFG.deadDays) || 90;
const STUCK = Number(CFG.stuckDays) || 60;
const num = n => (typeof n === 'number' ? n : Number(n)) || 0;
const MILL = 1e6; // raw IQD -> millions (matches dashboard formatter + seed)
const monAr = ['يناير','فبراير','مارس','أبريل','مايو','يونيو','يوليو','أغسطس','سبتمبر','أكتوبر','نوفمبر','ديسمبر'];
const monEn = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const now = new Date();
const curMon = now.getMonth();
const pid = v => Array.isArray(v) ? v[0] : v;
const pnm = v => Array.isArray(v) ? v[1] : (v || '');
const R = name => { try { const r = $(name).first().json.result; return Array.isArray(r) ? r : []; } catch (e) { return []; } };

// --- stock per product variant ---
const stock = new Map();
for (const g of R('Odoo Stock (read_group)')) {
  const id = pid(g.product_id); if (id == null) continue;
  stock.set(id, { onhand: num(g.quantity), value: num(g.value) });
}

// --- product details ---
const prod = new Map();
for (const p of R('Odoo Products (read)')) {
  prod.set(p.id, { name: p.display_name || pnm(p.categ_id) || ('#' + p.id), code: p.default_code || '',
    cat: pnm(p.categ_id) || '—', tmpl: pid(p.product_tmpl_id), cost: num(p.standard_price) });
}

// --- brand per template (optional; node may have failed) ---
const bf = CFG.brandField;
const tmplBrand = new Map();
for (const b of R('Odoo Brands (read)')) {
  const v = b[bf]; tmplBrand.set(b.id, (Array.isArray(v) ? v[1] : (v || null)) || '—');
}

// --- 90-day sales per product ---
const s90 = new Map();
for (const g of R('Odoo Sales 90d (read_group)')) s90.set(pid(g.product_id), num(g.product_uom_qty));

// --- monthly sales per product (for last-sale, total, seasonality) ---
const monthly = new Map(); // id -> {months:[12], last:Date|null, total}
for (const g of R('Odoo Sales Monthly (read_group)')) {
  const id = pid(g.product_id); if (id == null) continue;
  let dt = null;
  const rg = g.__range && (g.__range['create_date:month'] || g.__range['create_date']);
  if (rg && rg.from) dt = new Date(rg.from);
  else if (typeof g['create_date:month'] === 'string') dt = new Date(g['create_date:month']);
  const mi = dt && !isNaN(dt) ? dt.getMonth() : null;
  const qty = num(g.product_uom_qty);
  const last = g.create_date ? new Date(g.create_date) : null;
  if (!monthly.has(id)) monthly.set(id, { months: new Array(12).fill(0), last: null, total: 0 });
  const m = monthly.get(id);
  if (mi != null) m.months[mi] += qty;
  m.total += qty;
  if (last && (!m.last || last > m.last)) m.last = last;
}

// --- classify each in-stock product ---
function peakMonths(arr) {
  const sum = arr.reduce((a, b) => a + b, 0); if (sum <= 0) return [];
  const avg = sum / 12; return arr.map((v, i) => v >= avg * 1.3 && v > 0 ? i : -1).filter(i => i >= 0);
}
const products = [];          // stuck rows for dead_stock_products
let totalStockValue = 0;      // all in-stock value (millions)
const catAgg = new Map();     // cat -> {sku,val,dead}
const brandAgg = new Map();
const catMonths = new Map();  // cat -> [12] sales
const buckets = { '60': { dead: 0, dorm: 0, sku: 0 }, '90': { dead: 0, dorm: 0, sku: 0 }, '180': { dead: 0, dorm: 0, sku: 0 } };

for (const [id, st] of stock) {
  const p = prod.get(id) || { name: '#' + id, cat: '—', tmpl: null, cost: 0 };
  const brand = (p.tmpl != null && tmplBrand.get(p.tmpl)) || '—';
  const valM = (st.value > 0 ? st.value : st.onhand * p.cost) / MILL;
  totalStockValue += valM;
  const mo = monthly.get(id) || { months: new Array(12).fill(0), last: null, total: 0 };
  const idle = mo.last ? Math.floor((now - mo.last) / 864e5) : 9999;
  const sold90 = s90.get(id) || 0;

  // category seasonality accumulation (all in-stock products)
  if (!catMonths.has(p.cat)) catMonths.set(p.cat, new Array(12).fill(0));
  const cm = catMonths.get(p.cat); for (let i = 0; i < 12; i++) cm[i] += mo.months[i];
  if (!catAgg.has(p.cat)) catAgg.set(p.cat, { sku: 0, val: 0, dead: 0 });
  catAgg.get(p.cat).sku++; catAgg.get(p.cat).val += valM;
  if (!brandAgg.has(brand)) brandAgg.set(brand, { sku: 0, val: 0, dead: 0 });
  brandAgg.get(brand).sku++; brandAgg.get(brand).val += valM;

  if (idle < STUCK) continue; // still moving -> not stuck, skip from dead list

  const peaks = peakMonths(mo.months);
  const soon = peaks.includes(curMon) || peaks.includes((curMon + 1) % 12) || peaks.includes((curMon + 2) % 12);
  const passed = peaks.includes((curMon + 11) % 12) || peaks.includes((curMon + 10) % 12);
  let status = 'dead';
  if (soon) status = 'dormant';
  else if (passed) status = 'oos';
  const isDorm = status === 'dormant';

  const bk = idle >= 180 ? '180' : (idle >= 90 ? '90' : '60');
  buckets[bk].sku++; buckets[bk][isDorm ? 'dorm' : 'dead'] += valM;
  catAgg.get(p.cat).dead += isDorm ? 0 : valM;
  brandAgg.get(brand).dead += isDorm ? 0 : valM;

  const pkLabel = peaks.length ? { ar: peaks.map(i => monAr[i]).join('، '), en: peaks.map(i => monEn[i]).join(', ') } : { ar: 'لا نمط واضح', en: 'No pattern' };
  products.push({ product_id: id, name: p.name, category: p.cat, brand,
    on_hand: Math.round(st.onhand), value: Math.round(valM * 100) / 100,
    idle_days: idle === 9999 ? null : idle, sold_90: Math.round(sold90 * 100) / 100,
    peak_ar: pkLabel.ar, peak_en: pkLabel.en, status, updated_at: new Date().toISOString() });
}

// --- shape snapshot payloads (values in millions, matching the dashboard) ---
const r1 = n => Math.round(n * 10) / 10;
const seasonLabel = arr => { const pk = peakMonths(arr); if (!pk.length) return { ar: 'ثابت', en: 'Flat' }; return { ar: pk.map(i => monAr[i]).join('، '), en: pk.map(i => monEn[i]).join(', ') }; };
const intensity = arr => { const mx = Math.max(...arr, 0); return arr.map(v => mx <= 0 ? 0 : Math.min(3, Math.ceil(v / mx * 3))); };

const by_category = [...catAgg.entries()].map(([k, v]) => ({ name_ar: k, name_en: k, v: r1(v.dead) })).filter(x => x.v > 0).sort((a, b) => b.v - a.v).slice(0, 10);
const by_brand = [...brandAgg.entries()].map(([k, v]) => ({ name_ar: k, name_en: k, v: r1(v.dead) })).filter(x => x.v > 0).sort((a, b) => b.v - a.v).slice(0, 10);
const category_table = [...catAgg.entries()].map(([k, v]) => { const s = seasonLabel(catMonths.get(k) || []); return { name_ar: k, name_en: k, sku: v.sku, val: r1(v.val), dead: r1(v.dead), season_ar: s.ar, season_en: s.en }; }).sort((a, b) => b.dead - a.dead);
const brand_table = [...brandAgg.entries()].map(([k, v]) => ({ name_ar: k, name_en: k, sku: v.sku, val: r1(v.val), dead: r1(v.dead) })).sort((a, b) => b.dead - a.dead);
const topCats = category_table.slice(0, 7).map(c => c.name_ar);
const seaRows = topCats.map(k => ({ name_ar: k, name_en: k, d: intensity(catMonths.get(k) || new Array(12).fill(0)) }));
const nowList = topCats.filter(k => peakMonths(catMonths.get(k) || []).includes(curMon));
const soonList = topCats.filter(k => { const pk = peakMonths(catMonths.get(k) || []); return pk.includes((curMon + 1) % 12) || pk.includes((curMon + 2) % 12); });
const oosList = topCats.filter(k => { const pk = peakMonths(catMonths.get(k) || []); return pk.includes((curMon + 11) % 12) || pk.includes((curMon + 10) % 12); });

const bucketsSnap = [
  { label_ar: '60 – 90 يوم', label_en: '60 – 90 days', dead: r1(buckets['60'].dead), dorm: r1(buckets['60'].dorm), sku: buckets['60'].sku, min: 0 },
  { label_ar: '90 – 180 يوم', label_en: '90 – 180 days', dead: r1(buckets['90'].dead), dorm: r1(buckets['90'].dorm), sku: buckets['90'].sku, min: 1 },
  { label_ar: '180+ يوم', label_en: '180+ days', dead: r1(buckets['180'].dead), dorm: r1(buckets['180'].dorm), sku: buckets['180'].sku, min: 2 }
];
const seasonality = { months_ar: monAr.map(m => m[0]), months_en: ['J','F','M','A','M','J','J','A','S','O','N','D'], rows: seaRows,
  now: { ar: nowList.join(' · ') || '—', en: nowList.join(' · ') || '—' },
  soon: { ar: soonList.join(' · ') || '—', en: soonList.join(' · ') || '—' },
  oos: { ar: oosList.join(' · ') || '—', en: oosList.join(' · ') || '—' } };

const snapshots = [
  { key: 'total_stock_value', data: r1(totalStockValue) },
  { key: 'meta', data: { products_total: stock.size, generated_at: new Date().toISOString() } },
  { key: 'buckets', data: bucketsSnap },
  { key: 'by_category', data: by_category },
  { key: 'by_brand', data: by_brand },
  { key: 'category_table', data: category_table },
  { key: 'brand_table', data: brand_table },
  { key: 'seasonality', data: seasonality }
];
return [{ json: { snapshots, products } }];
